<?php if(php_sapi_name()!=='cli'){http_response_code(403);die('CLI only.');} require_once __DIR__.'/../config.php'; require_once __DIR__.'/../includes/Database.php'; require_once __DIR__.'/../includes/RedisClient.php'; require_once __DIR__.'/../includes/Monitor.php'; echo "[".date('Y-m-d H:i:s')."] Starting check...\n"; $db=Database::getInstance(); $sites=$db->fetchAll("SELECT * FROM `sites` WHERE is_active=1 ORDER BY display_order ASC"); if(empty($sites)){echo "No active sites.\n";exit(0);} $checked=0;$online=0;$offline=0; foreach($sites as $s){$lc=$db->fetch("SELECT checked_at FROM `checks` WHERE site_id=? ORDER BY checked_at DESC LIMIT 1",[$s['id']]);$iv=(int)($s['check_interval']??300);if($lc&&(time()-strtotime($lc['checked_at']))<$iv)continue;echo "  Checking: {$s['name']}... ";try{$r=Monitor::checkSite($s);Monitor::saveResult($s['id'],$r);$checked++;if($r['status']==='ok'){$online++;echo "OK ({$r['response_time']}ms)\n";}else{$offline++;echo strtoupper($r['status'])." - {$r['error_message']}\n";if($r['status']==='error'){$ei=$db->fetch("SELECT id FROM `incidents` WHERE site_id=? AND status!='resolved' AND started_at>DATE_SUB(NOW(),INTERVAL 1 HOUR) LIMIT 1",[$s['id']]);if(!$ei)$db->insert('incidents',['site_id'=>$s['id'],'title'=>"{$s['name']} 服务中断",'description'=>"自动检测异常: {$r['error_message']}",'severity'=>'major','status'=>'investigating','started_at'=>date('Y-m-d H:i:s')]);}}}catch(Exception $e){echo "ERROR: {$e->getMessage()}\n";$offline++;}if(count($sites)>1)usleep(500000);} echo "Done. Checked: {$checked}, Online: {$online}, Offline: {$offline}\n";